class Solution:
    def maximumCount(self, nums, queries):
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        cache = {}
        def prime(x):
            if x not in cache:
                cache[x] = is_prime(x)
            return cache[x]
        arr = list(nums)
        n = len(arr)
        res = []
        for idx, val in queries:
            arr[idx] = val
            best = 0
            for k in range(1, n):
                left = set(v for v in arr[:k] if prime(v))
                right = set(v for v in arr[k:] if prime(v))
                best = max(best, len(left) + len(right))
            res.append(best)
        return res

