class Solution:
    def maximumCount(self, nums, queries):
        def is_prime(x):
            if x < 2:
                return False
            if x % 2 == 0:
                return x == 2
            i = 3
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 2
            return True
        cache = {}
        def prime(x):
            if x not in cache:
                cache[x] = is_prime(x)
            return cache[x]
        arr = list(nums)
        n = len(arr)
        res = []
        for idx, val in queries:
            arr[idx] = val
            first = {}
            last = {}
            for i, v in enumerate(arr):
                if prime(v):
                    if v not in first:
                        first[v] = i
                    last[v] = i
            distinct = len(first)
            diff = [0] * (n + 2)
            for v in first:
                lo = first[v] + 1
                hi = last[v]
                if lo <= hi:
                    diff[lo] += 1
                    diff[hi + 1] -= 1
            best_overlap = 0
            run = 0
            for k in range(1, n):
                run += diff[k]
                if run > best_overlap:
                    best_overlap = run
            res.append(distinct + best_overlap)
        return res

