var maximumCount = function(nums, queries) {
    const cache = new Map();
    const isPrime = (x) => {
        if (cache.has(x)) return cache.get(x);
        let r = true;
        if (x < 2) r = false;
        else if (x % 2 === 0) r = (x === 2);
        else { for (let i = 3; i * i <= x; i += 2) { if (x % i === 0) { r = false; break; } } }
        cache.set(x, r);
        return r;
    };
    const arr = nums.slice();
    const n = arr.length;
    const res = [];
    for (const [idx, val] of queries) {
        arr[idx] = val;
        const first = new Map();
        const last = new Map();
        for (let i = 0; i < n; i++) {
            const v = arr[i];
            if (isPrime(v)) {
                if (!first.has(v)) first.set(v, i);
                last.set(v, i);
            }
        }
        const distinct = first.size;
        const diff = new Array(n + 2).fill(0);
        for (const [v, lo0] of first) {
            const lo = lo0 + 1;
            const hi = last.get(v);
            if (lo <= hi) { diff[lo] += 1; diff[hi + 1] -= 1; }
        }
        let bestOverlap = 0, run = 0;
        for (let k = 1; k < n; k++) {
            run += diff[k];
            if (run > bestOverlap) bestOverlap = run;
        }
        res.push(distinct + bestOverlap);
    }
    return res;
};
